DataView.HTMLTemplate:
@*@model SFP.Common.Models.RazorEngines.ViewModelRazorEngine*@

@{
	var childrenFolderTree = (List<dynamic>)Model.Data.ChildrenFolderTree;
	var currentFolderTree = (List<dynamic>)Model.Data.CurrentFolderTree;
	var itsmKnowledgeBase = (List<dynamic>)Model.Data.ITSMKnowledgeBase;
	var breadcrumb = (List<dynamic>)Model.Data.BreadCrumb;

	int itsmKnowledgeBaseCount = itsmKnowledgeBase.Count();
	int? parentFolderTreeID = currentFolderTree?.ToList().FirstOrDefault()?.ParentFolderTreeID is not System.DBNull ? currentFolderTree?.ToList().FirstOrDefault()?.ParentFolderTreeID : 0;
	int? currentFolderTreeID = currentFolderTree?.ToList().FirstOrDefault()?.ID;
}

@functions {

	void RenderCategory(List<dynamic> childrenFolderTree)
	{
		foreach(var item in childrenFolderTree){
			<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
				<div class="card-lmtl4 flex-fill-lmtl4">
					<a href="~/ContentView/Index/ITSMKnowledgeBaseDashboardView?filter=CurrentFolderTreeID:@item.FolderTreeID" class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
						<span class="badge-lmtl4 badge-pill-lmtl4 position-absolute-lmtl4 top-0-lmtl4 end-0-lmtl4 m-1-lmtl4 rounded-pill-lmtl4 bg-@item.ColorCssClass">@item.ITSMKnowledgeBaseCount</span>
						<span class="bg-@item.ColorCssClass rounded-pill-lmtl4 p-2-lmtl4 me-3-lmtl4">
							<i class="@item.IconCssClass d-block-lmtl4"></i>
						</span>

						<div class="flex-fill-lmtl4">
							<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@item.Name</h6>
						</div>
					</a>
				</div>
			</div>

		}
	}

	void RenderITSMKnowledgeBase(List<dynamic> itsmKnowledgeBase)
	{
		if(itsmKnowledgeBase is not null && itsmKnowledgeBase.Count > 0) {
			foreach(var item in itsmKnowledgeBase){

				<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
					<div class="card-lmtl4 flex-fill-lmtl4">
						<a href="~/Form/Detail/ITSMKnowledgeBaseSetting/@item.ID" class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
							<span class="me-3-lmtl4">
								<i class="@item.IconCssClass text-@item.ColorCssClass ph-2x d-block-lmtl4"></i>
							</span>

							<div class="flex-fill-lmtl4">
								<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@item.Title</h6>
								@item.CreateDate @item.AccountID
							</div>
						</a>
					</div>
				</div>
			}
		} else {
			<div class="col-xl-3 col-md-4 col-sm-6 d-flex-lmtl4">
				<div class="card-lmtl4 flex-fill-lmtl4">
					<div class="card-body-lmtl4 d-flex-lmtl4 align-items-center-lmtl4">
						<span class="me-3-lmtl4">
							<i class="ph-file-dotted text-grey ph-2x d-block-lmtl4"></i>
						</span>

						<div class="flex-fill-lmtl4">
							<h6 class="fw-semibold-lmtl4 mb-0-lmtl4">@Resx["NoKnowledgeBaseHere_ITSM"]</h6>
						</div>
					</div>
				</div>
			</div>

		}
	}

	void RenderBreadCrumb(List<dynamic> breadcrumb)
	{
		<div class="row">
			<div class="col-md-12">
				<div class="d-flex">
					<div class="breadcrumb-lmtl4">
						<a href="~/ContentView/Index/ITSMKnowledgeBaseDashboardView" class="breadcrumb-item-lmtl4 py-2-lmtl4"><i class="ph-book-bookmark me-1-lmtl4"></i></a>
						@{
							foreach(var item in breadcrumb){
								<a href="~/ContentView/Index/ITSMKnowledgeBaseDashboardView?filter=CurrentFolderTreeID:@item.FolderTreeID" class="breadcrumb-item-lmtl4 py-2-lmtl4">@item.Name</a>
							}
						}
					</div>
				</div>
			</div>
		</div>
	}

}

@if(childrenFolderTree is not null && childrenFolderTree.Count > 0) {

	<div class="card-lmtl4">
		<div class="card-header-lmtl4">
			<h5 class="mb-0-lmtl4">Vítejte ve znalostní bázi</h5>
		</div>

		<div class="card-body-lmtl4">
			<p>Znalostní báze slouží jako místo, kde najdete návody, odpovědi na časté otázky a řešení běžných problémů bez nutnosti zakládat nový požadavek.<br/>
			Obsah je rozdělen do složek podle typu požadavků a problémů. Díky tomuto členění můžete snadno najít oblast, která odpovídá vaší situaci.<br/>
			V jednotlivých složkách jsou k dispozici samostatné články, které vás krok za krokem provedou řešením konkrétního problému nebo vysvětlí, jak postupovat v dané situaci.<br/>
			Doporučujeme nejprve projít znalostní bázi a vyhledat odpovídající téma. Často zde najdete řešení rychleji, než kdybyste vytvářeli nový požadavek.</p>
		</div>
	</div>

}

@if(currentFolderTreeID is not null) {
	@{
		RenderBreadCrumb(breadcrumb.ToList());
	}
}

@if(childrenFolderTree is not null && childrenFolderTree.Count > 0) {

	<div class="row mb-2">
		<div class="col-md-12">
			<ul class="nav-lmtl4 nav-tabs-lmtl4 nav-tabs-underline-lmtl4 d-flex-lmtl4 align-items-baseline-lmtl4">
				<li class="nav-item-lmtl4">
					<span class="nav-link-lmtl4 active-lmtl4">
						<i class="ph-folder me-2-lmtl4"></i> @Resx["Folders_ITSM"]
					</span>
				</li>
				@if(parentFolderTreeID is not null && parentFolderTreeID != 0) {
					<li class="nav-item-lmtl4 ms-auto-lmtl4">
						<a href="~/ContentView/Index/ITSMKnowledgeBaseDashboardView?filter=CurrentFolderTreeID:@parentFolderTreeID" class="btn-lmtl4 d-block-lmtl4 px-4-lmtl4 py-1-lmtl4 btn-primary-lmtl4"><i class="ph-arrow-elbow-left-up d-block-lmtl4"></i></a>
					</li>
				} else if (parentFolderTreeID is not null) {
					<li class="nav-item-lmtl4 ms-auto-lmtl4">
						<a href="~/ContentView/Index/ITSMKnowledgeBaseDashboardView" class="btn-lmtl4 d-block-lmtl4 px-4-lmtl4 py-1-lmtl4 btn-primary-lmtl4"><i class="ph-arrow-elbow-left-up d-block-lmtl4"></i></a>
					</li>
				}
			</ul>
		</div>
	</div>

	<div class="row">
		@{
			RenderCategory(childrenFolderTree.ToList()); 
		}
	</div>

}

@if(childrenFolderTree is null || childrenFolderTree.Count <= 0) {

	<div class="row mb-2">
		<div class="col-md-12">
			<ul class="nav-lmtl4 nav-tabs-lmtl4 nav-tabs-underline-lmtl4 custom-underlineDanger">
				<li class="nav-item-lmtl4">
					<span class="nav-link-lmtl4 active-lmtl4">
						<i class="ph-file me-2-lmtl4"></i> @Resx["Articles_ITSM"] <span class="badge badge-pill bg-primary-lmtl4 ms-2-lmtl4">@itsmKnowledgeBaseCount</span>
					</span>
				</li>
			</ul>
		</div>
	</div>

	<div class="row">
		@{
			RenderITSMKnowledgeBase(itsmKnowledgeBase.ToList()); 
		}
	</div>

}

